<?php
 declare(strict_types=1); namespace tapmeppe\composer\blueprint; class Utilities { private static string $command; static function command(): string { return self::$command; } static function date(string $format = 'Y-m-d H:i:s'): string { return date($format); } static final function execute(...$command): array { $command = implode(' ', $command); echo '📢 Executing ❗' . self::$command = str_replace(' php ', ' #php# ', $command) . "❗\n"; exec( str_replace(' php ', sprintf(' "%s" ', PHP_BINARY), $command), $output, $result ); $output = trim(implode("\n", $output)); echo "$output\n\n"; return [$result == 0, $output, $result]; } static final function execute2(string $cwd, ...$commands): bool { foreach ($commands as $command) { list($success) = self::execute($cwd, $command); if (!$success) return false; } return true; } static function flatten(mixed $data, string $separator = '<({[:-x-:]})>', string $prefix = '', mixed $flat = []): mixed { foreach ($data as $key => $value) { if ( (is_array($value) && count($value)) || (is_object($value) && count(get_object_vars($value))) ) $flat = self::flatten($value, $separator, $prefix . $key . $separator, $flat); else $flat[$prefix . $key] = $value; } return $flat; } static final function getClass(object $instance): string { return Resources::getPathOptimised(get_class($instance)); } static final function getClassIdentifier(object $instance): string { return strtolower(basename(self::getClass($instance))); } static final function goto(string $directory): string { $command = count($pieces = explode(':', $directory)) > 1 ? ["$pieces[0]: &&"] : []; $command[] = "cd \"$directory\" &&"; return implode(' ', $command); } static function merge(mixed $left, mixed $right, string $separator = '<({[:-x-:]})>'): mixed { return self::nest( array_merge(self::flatten($left, $separator), self::flatten($right, $separator)), $separator ); } static function nest(mixed $flat, string $separator = '<({[:-x-:]})>'): mixed { $data = []; foreach ($flat as $pieces => $value) { $temporary = &$data; $keys = explode($separator, (string)$pieces); $last = count($keys) - 1; foreach ($keys as $i => $key) { if ($i == $last) { if (!(isset($temporary[$key]) && is_array($temporary[$key]))) $temporary[$key] = $value; } else { if (!isset($temporary[$key])) $temporary[$key] = []; $temporary = &$temporary[$key]; } } unset($temporary); } return $data; } static function replace(string $haystack, array $needles, array $raw = []): string { $map = ['@{UMBRELLA}' => TAPMEPPE_UMBRELLA] + $raw; foreach ($needles as $placeholder => $value) $map["($placeholder)"] = $value; return strtr($haystack, $map); } static function report(mixed $data): void {} } 